const stdout = $input.item.json.stdout || '';

if (stdout.includes('[NO_OUTLOOK]')) {
  return [{ json: { send_email: false, reason: 'No outlook data available' } }];
}

if (!stdout.includes('[OUTLOOK]')) {
  throw new Error(`Unexpected output from rate outlook fetch:\n${stdout}`);
}

// Parse the JSON line after [OUTLOOK]
const lines = stdout.trim().split('\n');
const jsonLine = lines.find(l => l.startsWith('[{'));
const outlooks = JSON.parse(jsonLine);

// Build email body
const EMOJI = { cheap: '🟢', average: '🟡', expensive: '🔴' };
const lines_out = outlooks.map(o => {
  const emoji = EMOJI[o.rate_outlook] || '⚪';
  const hours = o.sunshine_hours ? `${o.sunshine_hours}h sunshine` : 'no sunshine data';
  return `${emoji} ${o.date}  ${o.rate_outlook.toUpperCase()}  (${hours})\n   ${o.outlook_reason}`;
});

const body = [
  'Agile Rate Outlook — next 3 days',
  '================================',
  ...lines_out,
  '',
  'Note: This is a qualitative forecast based on predicted sunshine.',
  'Confirmed Agile rates are published daily at ~16:00.',
].join('\n');

return [{ json: { send_email: true, subject: `Agile Rate Outlook: ${outlooks[0].rate_outlook}`, body, outlooks } }];

